+    const exps = new Float32Array(logits.length);
+    let sum = 0;
+
+    for (let i = 0; i < logits.length; i++) {
+      exps[i] = Math.exp(logits[i] - max);
+      sum += exps[i];
+    }
+
+    for (let i = 0; i < exps.length; i++) {
+      exps[i] /= sum;
+    }
+
+    return exps;
+  }
+
+  private sampleAction(probs: Float32Array): number {
