+    // Softmax
+    let sum = 0;
+    for (let j = 0; j < seqLength; j++) {
+      rowScores[j] = Math.exp(rowScores[j]! - max);
+      sum += rowScores[j]!;
+    }
+    for (let j = 0; j < seqLength; j++) {
+      rowScores[j]! /= sum;
