+  // Chunk buffer - O(chunkSize^2) memory
+  const chunkScores = new Float32Array(chunkSize * seqLength);
+  const rowMax = new Float32Array(chunkSize).fill(-Infinity);
+  const rowSum = new Float32Array(chunkSize).fill(0);
