+    // Softmax
+    for (let i = 0; i < seqLength; i++) {
+      let max = -Infinity;
+      for (let j = 0; j < seqLength; j++) {
+        max = Math.max(max, scores[i * seqLength + j]!);
+      }
+
+      let sum = 0;
+      for (let j = 0; j < seqLength; j++) {
+        const exp = Math.exp(scores[i * seqLength + j]! - max);
+        scores[i * seqLength + j] = exp;
+        sum += exp;
+      }
