+    for (let i = 0; i < seqLength; i++) {
+      for (let k = 0; k < headDim; k++) {
+        let sum = 0;
+        for (let j = 0; j < seqLength; j++) {
+          sum += scores[i * seqLength + j]! * value[j * headDim + k]!;
